import{P as t,R as c,L as m,F as o,bf as M,E as s,D as i,H as d,I as g,G as p,bn as R,bo as P,j as I,bi as A}from"./element-plus-CK39Ztmh.js";import{_ as H}from"./index-8LZsSjLz.js";const G={apiDebugger:{title:"📖 接口调试 - 使用说明",intro:"接口调试是一个轻量级 HTTP 客户端，类似 Postman。你可以快速发送请求、查看响应，并将调试好的接口保存为测试用例。支持 cURL 导入、变量替换、请求历史等功能。",sections:[{heading:"发送请求",icon:"🚀",steps:["**选择请求方法**：点击方法下拉框，选择 GET / POST / PUT / PATCH / DELETE","**输入请求地址**：在 URL 栏输入完整地址，如 `https://httpbin.org/post`。支持变量替换，如 `{{base_url}}/api/users`","**设置超时**：URL 右侧的超时输入框，默认 30 秒，范围 1-60 秒","**填写请求参数**：切换下方标签页","  - **请求体**：选择格式（JSON / Form / Text / XML），JSON 格式有「格式化」按钮自动修正缩进","  - **请求头**：添加自定义 Header，如 `Authorization: Bearer {{token}}`","  - **Query 参数**：添加 URL 查询参数，如 `page=1&size=10`","**发送请求**：点击「发送」按钮，或按快捷键 **Ctrl+Enter**（Mac 为 Cmd+Enter）"]},{heading:"查看响应",icon:"📡",text:"请求发送后，响应面板会显示：",items:["**状态码**：彩色标签显示 HTTP 状态码（2xx 绿色、4xx 橙色、5xx 红色）","**耗时**：请求从发送到收到响应的总时间（毫秒）","**大小**：响应体的字节数","**响应体**：默认格式化显示 JSON，支持切换到原始文本","**响应头**：展示所有响应 Header","**请求详情**：展示实际发送的请求 URL、方法、Header、Body","**复制**：点击「复制」按钮将响应体复制到剪贴板"]},{heading:"保存到接口库",icon:"💾",text:"调试成功后，点击响应面板的「保存到接口库」按钮：",steps:["系统自动填充接口名称（方法 + URL 最后一段）","选择「所属分组」，用例会归入该分组下","可选填写「接口描述」","点击「确定」保存，之后在「接口库」标签页可找到该用例","提示：如果响应状态码不是 2xx，系统会提醒你确认是否仍要保存"]},{heading:"cURL 导入",icon:"📋",text:"点击工具栏的「导入 cURL」按钮，粘贴 cURL 命令（从浏览器开发者工具 Network 面板复制），系统自动解析出请求方法、URL、请求头和请求体，填入调试区。",items:["支持标准 cURL 语法，包括 `-X`、`-H`、`-d`、`--data`、`--header` 等参数","导入后可修改并发送，也可以直接保存到接口库"]},{heading:"变量替换",icon:"🔀",text:"在 URL、请求头、请求体中使用 `{{变量名}}` 格式引用变量。点击输入框右侧的「变量」按钮可查看和插入可用变量：",items:["**环境变量**：选择环境后自动可用，如 `{{base_url}}`、`{{API_KEY}}`","**全局变量**：在「变量管理」中定义，所有环境共享","**动态变量**：每次执行自动生成新值","  - `{{$timestamp}}` - 当前 Unix 时间戳（秒）","  - `{{$random_int}}` - 1~10000 随机整数","  - `{{$random_string}}` - 10 位随机字母数字","  - `{{$uuid}}` - 随机 UUID","  - `{{$datetime}}` - 当前日期时间（YYYY-MM-DD HH:MM:SS）","**优先级**：环境变量 > 全局变量（同名时环境变量覆盖）"]},{heading:"请求历史",icon:"📜",text:"点击工具栏「历史」按钮打开历史抽屉：",items:["记录最近 50 条请求，显示方法、URL、状态码、时间","**再次请求**：点击按钮重新发送该请求","**加载**：将历史记录加载到调试区继续编辑","**删除**：移除单条历史记录","**清空历史**：一键清空所有记录"]}]},caseList:{title:"📖 接口库 / 用例管理 - 使用说明",intro:"接口库是所有测试用例的集中管理区域。左侧为分组树，右侧为用例列表。用例可以从接口调试保存、从外部文件导入、或手动创建。",sections:[{heading:"分组管理（左侧栏）",icon:"📁",text:"左侧是接口分组树，用文件夹方式组织用例：",items:["**新建根分组**：点击左上角 ⋮ 菜单，选择「新建根分组」，输入名称和描述","**新建子分组**：先选中一个分组，再点击 ⋮ 菜单选择「新建子分组」","**编辑分组**：选中分组后点击 ⋮ 菜单选择「编辑分组」","**删除分组**：选中分组后点击 ⋮ 菜单选择「删除分组」，**注意：删除分组会同时删除其下所有用例**","**选择分组**：点击分组节点，右侧用例列表会过滤显示该分组下的用例","每个分组节点旁显示用例数量徽章"]},{heading:"用例操作（右侧列表）",icon:"📝",items:["**新建用例**：点击「新建用例」按钮，填写接口信息、请求参数和断言规则","**编辑用例**：点击用例行的编辑图标，打开编辑抽屉修改用例配置","**运行用例**：点击行尾 ▶ 按钮，选择环境后运行，查看执行结果","**删除用例**：点击删除图标，确认后永久删除（不可恢复）","**搜索**：在搜索框输入关键词，按名称或 URL 实时过滤","**分页**：底部支持每页 10/20/50 条切换"]},{heading:"环境选择",icon:"🌐",text:"工具栏左侧的环境下拉框决定运行用例时使用哪套变量：",items:["选择环境后，用例中的 `{{变量名}}` 会被替换为该环境对应的值","如果用例 URL 是**相对路径**（如 `/api/v1/users`），会自动拼上环境的 `base_url`","如果用例 URL 是**绝对路径**（如 `http://xxx.com/api/...`），不会自动替换域名，需手动改为 `{{base_url}}/api/...`","**不选则使用默认环境**（在环境管理中标记为默认的那个）","点击 ⚙ 按钮打开环境管理器，可新建/编辑/删除环境"]},{heading:"导入用例",icon:"📥",text:"支持从外部文件批量导入用例，点击工具栏的「导入」按钮：",items:["**Postman**：导入 Postman Collection 导出的 JSON 文件，自动解析请求和文件夹结构","**Swagger/OpenAPI**：导入 OpenAPI 3.0 规范的 JSON/YAML 文件，路径参数自动转为 `{{参数名}}`","**JMeter**：导入 .jmx 文件，自动解析 HTTP Sampler 为用例","**cURL**：粘贴 cURL 命令快速创建用例（cURL 导入在「接口调试」标签页内）"]},{heading:"导出 JMX",icon:"📤",text:"勾选一个或多个用例，点击「导出 JMX」按钮，将用例导出为 JMeter 可执行的 .jmx 脚本文件。可在 JMeter GUI 中打开运行。"}]},caseEditor:{title:"📖 用例编辑 - 使用说明",intro:"用例编辑器用于创建和修改测试用例，配置请求参数、断言规则和变量提取。从接口库点击编辑或新建用例时打开。",sections:[{heading:"基本信息",icon:"📋",items:["**用例名称**：简洁描述接口用途，如「登录接口-正常流程」「查询用户-未授权」","**请求方法**：GET / POST / PUT / PATCH / DELETE","**URL**：接口地址，支持 `{{base_url}}/api/...` 格式的变量占位符","**Content-Type**：选择请求体格式（JSON / Form / Text / XML / None），影响请求头的 Content-Type"]},{heading:"请求体配置",icon:"📦",items:["**JSON**：最常用，输入 JSON 格式请求体，支持 `{{变量名}}` 占位符","**Form Data**：键值对表单，每个字段支持变量","**Raw**：原始文本格式，适合 XML 或自定义格式","**None**：无请求体（GET/DELETE 请求通常选此项）"]},{heading:"断言规则",icon:"✅",text:"断言用于验证接口返回是否符合预期。运行用例时，系统逐条检查断言，全部通过才算成功。点击「添加断言」配置：",items:["**字段**：要检查的响应字段，常用如下","  - `status_code` - HTTP 状态码","  - `body.code` - 响应体 JSON 中的 code 字段","  - `body.data.token` - 嵌套字段用点号分隔","  - `response_time` - 响应时间（毫秒）","  - `header.Content-Type` - 响应头字段","**比较方式**：等于、不等于、包含、不包含、大于、小于、大于等于、小于等于、正则匹配、为空、不为空","**期望值**：预期结果，如 `200`、`0`、`success`","**注意**：无断言规则时，系统默认检查状态码是否为 2xx/3xx"]},{heading:"变量提取",icon:"🔗",text:"从响应中提取值保存为变量，供后续步骤或其他用例使用。点击「添加提取」配置：",items:['**JSONPath 提取**：从响应 JSON 中按路径提取，如 `data.token` 提取 `{ "data": { "token": "abc123" } }` 中的 `abc123`',"**正则提取**：用正则表达式从响应文本中匹配提取，如 `token=(.+?)&` 提取 token 值","**Header 提取**：从响应头中提取指定字段值，如 `Set-Cookie`","**变量名**：提取的值保存为此名称，后续步骤用 `{{变量名}}` 引用","提取的变量会自动保存，整个场景执行期间有效"]},{heading:"变量使用",icon:"🔀",text:"在 URL、Headers、请求体中使用 `{{变量名}}` 格式引用变量。运行时系统自动替换所有占位符。",items:["变量来源优先级：**环境变量 > 全局变量**（同名时环境变量覆盖全局变量）","内置动态变量每次执行生成新值：`{{$timestamp}}`、`{{$random_int}}`、`{{$random_string}}`、`{{$uuid}}`、`{{$datetime}}`","场景执行时，前一步提取的变量后续步骤可直接引用（如登录后用 `{{token}}`）"]}]},environmentManager:{title:"📖 环境管理 - 使用说明",intro:"环境管理用于维护不同运行环境（开发、测试、生产等）的配置信息，包括基础 URL 和自定义变量。通过环境变量，同一套用例可以在不同环境下运行，无需修改用例本身。",sections:[{heading:"什么是环境变量",icon:"❓",text:"环境变量是特定环境下的配置参数。不同环境（开发/测试/生产）通常有不同的服务器地址、API Key、数据库连接等。例如：",items:["开发环境：`base_url` = `http://localhost:5001`","测试环境：`base_url` = `http://test-api.example.com`","生产环境：`base_url` = `https://api.example.com`","切换环境后，同一个用例 `{{base_url}}/api/users` 会请求不同服务器"]},{heading:"创建环境",icon:"➕",steps:["点击「新建环境」按钮","填写**环境名称**，如「开发环境」「测试环境」「生产环境」","填写**基础 URL**，如 `http://localhost:5001` 或 `https://api.example.com`（不含末尾斜杠）","可选：开启「设为默认」，运行用例时不选环境就使用此环境","在「自定义变量」区域添加键值对，如 `API_KEY` = `abc123`、`DB_HOST` = `192.168.1.100`","点击「创建」保存"]},{heading:"变量引用规则",icon:"🔀",text:"在用例的 URL、Headers、请求体中使用 `{{变量名}}` 格式引用变量：",items:["`{{base_url}}` - 自动注入，值为环境的「基础 URL」字段","`{{API_KEY}}` - 自定义变量，值为你在环境中配置的值","**变量优先级**：环境变量 > 全局变量（同名时环境变量覆盖全局变量）","**URL 拼接**：如果用例 URL 不以 `http://` 或 `https://` 开头，会自动拼上 `base_url`","**绝对路径 URL 不会自动替换域名**，需手动改为 `{{base_url}}/api/...`"]},{heading:"使用示例",icon:"💡",text:"假设你创建了「测试环境」，base_url 为 `http://test-api.example.com`，自定义变量 `token` = `test-abc123`：",code:`用例 URL:     {{base_url}}/api/v1/users
用例 Header:  Authorization: Bearer {{token}}

运行时自动替换为:
URL:     http://test-api.example.com/api/v1/users
Header:  Authorization: Bearer test-abc123`},{heading:"导入/导出环境",icon:"🔄",items:["**导出**：点击「导出环境」，将所有环境配置下载为 JSON 文件，方便备份或分享给团队","**导入**：点击「导入环境」，选择 JSON 文件。同名环境会更新，新环境会创建"]}]},globalVariableManager:{title:"📖 全局变量管理 - 使用说明",intro:"全局变量在所有环境和所有用例中共享。适合存放跨环境通用的配置值，如公共参数、固定 Token、加密密钥等。",sections:[{heading:"全局变量 vs 环境变量",icon:"⚖️",table:{cols:[{key:"prop",label:"对比项",width:120},{key:"global",label:"全局变量",width:180},{key:"env",label:"环境变量"}],rows:[{prop:"作用范围",global:"所有环境共享",env:"仅当前环境"},{prop:"优先级",global:"较低（可被环境变量覆盖）",env:"较高（覆盖同名全局变量）"},{prop:"适用场景",global:"公共参数、固定值",env:"环境特有的地址、密钥"},{prop:"引用方式",global:"`{{变量名}}`",env:"`{{变量名}}`（相同语法）"},{prop:"加密支持",global:"支持",env:"不支持"}]}},{heading:"创建变量",icon:"➕",steps:["点击「添加变量」按钮","输入**变量名**（只能包含字母、数字、下划线、中划线、点号）","输入**变量值**","可选：填写**描述**，方便团队理解用途","可选：开启**加密存储**，值在数据库中加密保存，列表中显示为 ******","点击保存"]},{heading:"管理操作",icon:"⚙️",items:["**编辑**：点击变量行的编辑按钮修改值","**删除**：点击删除按钮，确认后删除单个变量","**批量删除**：勾选多个变量后点击「批量删除」","**导入**：点击「导入」上传 JSON 文件批量创建变量","**导出**：点击「导出」将所有变量下载为 JSON 文件","**调试**：点击「调试」按钮，输入变量名测试替换效果"]},{heading:"内置动态变量",icon:"⚡",text:"系统内置 5 个动态变量，无需创建，每次执行时自动生成新值：",items:["`{{$timestamp}}` - 当前 Unix 时间戳（秒），如 `1717000000`","`{{$random_int}}` - 1~10000 的随机整数","`{{$random_string}}` - 10 位随机字母数字字符串","`{{$uuid}}` - 随机 UUID，如 `a1b2c3d4-e5f6-7890-abcd-ef1234567890`","`{{$datetime}}` - 当前日期时间，格式 `YYYY-MM-DD HH:MM:SS`"]},{heading:"加密变量",icon:"🔒",text:"开启「加密存储」后，变量值在数据库中用 AES 加密保存，列表中显示为 `******`。运行时自动解密使用。适合存储 API Key、密码、Token 等敏感信息。加密变量在导出时也会加密处理。"}]},scenarioList:{title:"📖 场景管理 - 使用说明",intro:"测试场景是将多个接口用例按顺序编排成的测试流程，模拟用户的完整操作路径（如：登录→查询→下单→支付）。场景支持步骤间数据传递、数据驱动、定时执行和 CI/CD 集成。",sections:[{heading:"创建场景",icon:"➕",steps:["点击「新建场景」按钮","输入**场景名称**（必填），如「用户登录流程」「订单创建全链路」","输入**描述**（可选），说明场景用途","点击「确定」创建后，自动进入场景编辑器","在编辑器中添加步骤、编排顺序、配置数据驱动"]},{heading:"场景列表操作",icon:"📋",items:["**搜索**：在搜索框输入关键词，按场景名称和描述过滤","**环境选择**：选择执行环境，运行场景时使用该环境的变量","**状态开关**：启停开关控制场景是否可用，停用的场景无法运行","**编辑**：点击编辑图标进入场景编辑器","**删除**：点击删除图标，二次确认后删除（会同时删除所有步骤）"]},{heading:"运行场景",icon:"▶️",steps:["确保场景状态为「启用」且已选择执行环境","点击场景行的 ▶ 运行按钮","系统按步骤顺序逐个执行，实时显示进度","每步执行完显示成功/失败状态和耗时","执行完成后查看汇总报告（总步骤、成功数、失败数、总耗时）","如果某步失败且场景开启了「失败即停」，后续步骤会跳过"]},{heading:"定时任务（Cron）",icon:"⏰",text:"点击场景行的「设置计划」链接，配置定时自动执行：",items:["**Cron 表达式**：标准 5 位格式 `分 时 日 月 周`","  - `0 8 * * *` = 每天 8:00","  - `0 9 * * 1-5` = 工作日 9:00","  - `*/30 * * * *` = 每 30 分钟","  - `0 0 1 * *` = 每月 1 号 0:00","**Webhook 告警**：填写飞书/钉钉/企业微信机器人 Webhook URL，执行完成后自动推送结果通知","**启用/暂停**：创建后可随时暂停或恢复定时任务","定时任务独立运行，不影响手动执行"]},{heading:"CI/CD Webhook 集成",icon:"🔗",text:"点击场景行的 CI/CD 按钮，获取 Webhook 触发命令：",items:["系统生成 cURL 命令，可直接嵌入 GitLab CI / Jenkins / GitHub Actions 流水线","每次触发会异步执行场景，返回任务 ID","结合 Webhook 告警，执行结果自动推送到群聊","每个场景有独立的 Webhook Token，确保安全性"]},{heading:"执行历史",icon:"📜",text:"点击场景行的历史按钮，查看该场景的所有执行记录：",items:["显示每次执行的状态（成功/失败/运行中）、步骤统计、耗时、执行时间","支持查看 Allure 详细报告（如果配置了报告路径）","支持从历史记录重新运行场景"]}]},scenarioEditor:{title:"📖 场景编辑器 - 使用说明",intro:"场景编辑器用于编排测试步骤、配置数据驱动、查看执行历史。从场景列表点击编辑进入。",sections:[{heading:"顶部操作栏",icon:"🎛️",items:["**返回**：点击返回按钮回到场景列表","**场景名称**：直接点击修改，失焦后自动保存","**环境选择**：选择运行场景时使用的环境","**保存**：保存场景配置（名称、描述等）","**添加步骤**：打开用例选择对话框，从接口库中选择用例添加为步骤","**运行场景**：立即执行当前场景"]},{heading:"步骤编排",icon:"📝",text:"场景步骤按从上到下的顺序依次执行：",steps:["点击「添加步骤」，在弹出的对话框中搜索和勾选接口用例","支持一次选择多个用例批量添加","步骤添加后可**拖拽调整顺序**","每个步骤可以**启用/禁用**（禁用的步骤执行时跳过）","每个步骤可以**删除**","点击步骤的「编辑覆盖」可为该步骤设置独立的变量覆盖（不影响原用例）"]},{heading:"步骤间数据传递",icon:"🔗",text:"场景中的步骤通过变量提取实现数据传递。典型流程：",items:["**步骤 1（登录）**：发送登录请求，在「变量提取」中从响应提取 `token`（JSONPath: `data.token`）","**步骤 2（查询）**：在请求头中使用 `Authorization: Bearer {{token}}`","系统按顺序执行，前一步提取的变量后续步骤自动可用","变量覆盖：可以为某个步骤单独设置变量值，覆盖全局/环境变量"]},{heading:"数据驱动",icon:"📊",text:"切换到「数据驱动」标签页，上传 CSV 数据文件实现参数化执行：",items:["**CSV 格式**：第一行为变量名（如 `username,password`），后续行为数据","场景会按每行数据迭代执行一次，行内变量用 `{{变量名}}` 引用","例如：上传 10 行用户数据，场景会执行 10 次，每次用不同用户登录","执行报告显示每次迭代的结果"]},{heading:"执行历史",icon:"📜",text:"切换到「执行历史」标签页，查看该场景的所有执行记录：",items:["显示汇总统计：总执行次数、成功次数、失败次数","表格显示每次执行的状态、步骤统计、耗时、时间","点击「查看报告」打开 Allure 详细报告（如有）"]}]},suiteManager:{title:"📖 测试套件 - 使用说明",intro:"测试套件将多个测试用例组合在一起，一键批量执行并生成综合测试报告。适合回归测试、冒烟测试等需要批量运行多个接口的场景。",sections:[{heading:"创建套件",icon:"➕",steps:["点击「新建套件」按钮","输入**套件名称**（必填），如「冒烟测试套件」「v2.0 回归测试」","输入**描述**（可选），说明套件用途","在「关联用例」下拉框中搜索并选择要包含的用例（支持远程搜索）","点击「保存」创建套件"]},{heading:"管理套件",icon:"⚙️",items:["**查看**：点击查看详情，展示套件包含的所有用例列表（名称、方法、URL、顺序）","**编辑**：修改套件名称、描述和关联用例","**删除**：确认后删除套件（不会删除用例本身）","**分页**：支持每页 10/20/50 条切换","**状态**：显示最近执行状态（通过/失败/运行中/未执行）和执行时间"]},{heading:"执行套件",icon:"▶️",steps:["点击套件的 ▶ 执行按钮","系统按用例顺序逐个执行","执行完成后弹出结果对话框，显示","  - 总用例数、通过数（绿色）、失败数（红色）、总耗时","  - 每个用例的执行结果：状态、耗时、错误信息","通过的用例绿色标记，失败的用例红色标记并显示错误原因"]}]},mockService:{title:"📖 Mock 服务 - 使用说明",intro:"Mock 服务用于模拟后端接口返回，在后端未开发完成时提供假数据，让前端开发和测试可以并行。支持从 Swagger 导入规则、请求日志查看等功能。",sections:[{heading:"创建 Mock 项目",icon:"➕",steps:["点击「新建项目」按钮","输入**项目名称**，如「用户服务 Mock」「订单系统 Mock」","输入**URL 标识**（必填），如 `user-service`。Mock 地址预览会实时显示","输入**描述**（可选）","点击「保存」创建项目"]},{heading:"配置 Mock 规则",icon:"⚙️",text:"选中项目后，点击「新建规则」配置接口返回：",items:["**规则名称**：描述此规则用途，如「获取用户列表-正常返回」","**请求方法**：GET / POST / PUT / DELETE / PATCH","**请求路径**：如 `/users`、`/users/:id`、`/login`","**响应状态码**：HTTP 状态码，如 200、404、500",'**响应头**：JSON 格式，如 `{"Content-Type": "application/json"}`','**响应体**：JSON 格式的返回数据，如 `{"code": 0, "data": []}`',"**延迟**：模拟网络延迟（毫秒），0 表示无延迟","**优先级**：数字越大优先级越高，多条规则匹配时返回优先级最高的","**启用/禁用**：开关控制规则是否生效"]},{heading:"从 Swagger 导入",icon:"📥",text:"点击「从 Swagger 导入」按钮，选择 Swagger/OpenAPI JSON 或 YAML 文件，系统自动将所有接口路径和方法创建为 Mock 规则，大幅减少手动配置工作。"},{heading:"请求日志",icon:"📜",text:"选中项目后，下方显示请求日志表格：",items:["记录所有发往该 Mock 项目的请求","显示：时间、请求方法、路径、响应状态码、耗时（毫秒）、匹配的规则名称","点击「刷新」按钮更新日志","方便排查 Mock 规则是否正确匹配"]}]},dataFactory:{title:"📖 测试数据工厂 - 使用说明",intro:"数据工厂用于批量生成测试数据，支持 10 种数据规则，可导出为 JSON/CSV 格式，或直接绑定场景进行数据驱动执行。",sections:[{heading:"创建数据模板",icon:"➕",steps:["点击「新建模板」从空白开始，或点击「从预设创建」选择预设模板（用户注册、商品数据、订单数据等）","输入**模板名称**和**描述**","设置**生成行数**（1-1000）","可选：**关联场景**，绑定后可直接用生成的数据驱动执行该场景"]},{heading:"定义字段规则",icon:"📋",text:"每个字段配置一个数据生成规则：",items:["**字段名**：英文标识，如 `username`、`phone`（CSV 导出时作为列名）","**中文标签**：可选，方便理解","**规则类型**：从下拉框选择（见下方规则类型表）","**规则参数**：根据类型不同显示不同的配置项","点击字段卡片的上下箭头调整顺序，点击删除按钮移除","使用顶部快捷标签可一键添加常用字段（手机号、邮箱、用户名等）"]},{heading:"数据规则类型",icon:"📊",table:{cols:[{key:"type",label:"规则类型",width:100},{key:"desc",label:"说明",width:200},{key:"config",label:"配置项"},{key:"example",label:"示例",width:140}],rows:[{type:"固定值",desc:"所有行使用相同值",config:"固定值",example:'"admin"'},{type:"枚举值",desc:"从给定列表中随机选择",config:"候选值列表（支持手动输入）",example:'"男", "女"'},{type:"递增数字",desc:"从起始值按步长递增",config:"前缀、起始值、步长",example:'"ID_001", "ID_002"'},{type:"手机号",desc:"随机 11 位手机号",config:"号段前缀",example:"13800138000"},{type:"邮箱",desc:"随机邮箱地址",config:"用户名前缀、域名",example:"test_abc@example.com"},{type:"用户名",desc:"随机用户名",config:"前缀、后缀长度",example:"user_a8x3k"},{type:"UUID",desc:"随机 UUID",config:"标准格式 / 短格式（无横杠）",example:"a1b2c3d4-..."},{type:"时间戳",desc:"当前 Unix 时间戳",config:"秒 / 毫秒",example:"1717000000"},{type:"日期偏移",desc:"基于当前日期偏移",config:"偏移天数、日期格式",example:"2026-06-10"},{type:"环境变量",desc:"引用环境变量值",config:"变量名、默认值",example:"{{API_KEY}}"}]}},{heading:"预览与导出",icon:"📤",items:["**刷新预览**：点击按钮实时预览生成的数据（表格形式展示）","**生成数据集**：将数据保存到服务端，供数据驱动执行使用","**导出 CSV**：下载为 CSV 文件，可用 Excel 打开","**导出 JSON**：下载为 JSON 数组格式","**数据驱动执行**：如果已关联场景，直接用生成的数据运行该场景"]},{heading:"预设模板",icon:"📦",text:"点击「从预设创建」可快速开始，内置 5 个常用模板：",items:["**用户注册**：用户名、手机号、邮箱、密码、昵称","**商品数据**：商品名、价格、库存、分类、SKU","**订单数据**：订单号、金额、状态、用户ID、商品ID","**接口压测**：大量随机数据字段，适合压测场景","**日期时间**：各种格式的日期时间数据"]}]},jmeterAssistant:{title:"📖 JMeter 助手 - 使用说明",intro:"JMeter 助手是一个可视化 JMeter 脚本生成器，无需手写 XML 即可创建 .jmx 压测脚本。支持从接口库导入、内置并发压测、脚本历史管理。",sections:[{heading:"三步生成压测脚本",icon:"🚀",steps:["**第 1 步 · 选择接口**：从接口库导入 API 用例，或使用模板快速创建脚本，也可以导入已有的 .jmx 文件","**第 2 步 · 配置压测参数**：在树形编辑器中配置线程组（并发数/循环次数）、HTTP 请求、断言、提取器等元件","**第 3 步 · 导出与验证**：生成 .jmx 文件下载，或使用内置并发测试工具直接验证"]},{heading:"第 1 步：选择接口",icon:"📥",items:["**模板快速创建**：点击模板卡片一键生成基础脚本（含线程组 + HTTP 请求 + 监听器）","**从接口库导入**：右侧显示接口库用例列表，勾选后点击「导入到脚本」自动生成 HTTP Sampler","**导入 .jmx 文件**：点击导入卡片，选择已有的 JMeter 脚本文件解析","**分组过滤**：可按接口分组筛选用例","**搜索**：按接口名称或 URL 搜索"]},{heading:"第 2 步：配置元件",icon:"⚙️",text:"左侧树形编辑器展示脚本结构，右侧属性面板编辑选中元件的参数。支持的元件类型：",items:["**线程组**：配置并发线程数、Ramp-Up 时间、循环次数、持续时间","**HTTP 请求**：配置 URL、方法、请求头、请求体。支持「调试此请求」和「保存到接口库」","**断言**（9 种）：响应断言、JSON 断言、持续时间断言、BeanShell 断言、JSR223 断言、大小断言、XPath 断言、比较断言、XML 断言","**提取器**（2 种）：正则提取器、JSON 提取器，用于参数化","**定时器**（4 种）：固定定时器、均匀随机定时器、高斯随机定时器、同步定时器","**前置/后置处理器**：BeanShell、JSR223 脚本，支持 AI 辅助编写","**逻辑控制器**：如果、循环、While、事务、吞吐量、仅一次、ForEach、Switch、随机、交替、Include","**配置元件**：HTTP Cookie 管理器、HTTP 请求默认值、CSV 数据文件、JDBC 连接/采样器、用户参数","**监听器**：查看结果树、汇总报告、聚合报告、响应时间图、InfluxDB 后端监听"]},{heading:"第 3 步：导出与验证",icon:"📤",items:["**生成预览**：点击按钮生成 JMX XML 预览","**下载 .jmx**：下载 JMeter 脚本文件，兼容 JMeter 5.1.1 ~ 5.6","**内置并发测试**：直接在平台内运行压测，配置并发数（1-200）、持续时间（3-60 秒）、预热时间","**压测结果**：显示总请求数、成功/失败数、TPS、P50/P90/P95/P99 响应时间、状态码分布、错误统计、每 URL 聚合数据","**查看结果树**：查看每个请求的详细信息（Sampler 结果、请求内容、响应内容）"]},{heading:"脚本历史",icon:"📜",text:"点击「脚本历史」按钮查看保存过的脚本：",items:["每个用户独立的脚本历史（按登录账号隔离）","显示脚本名称、创建时间、线程数、采样器数","点击可加载历史脚本继续编辑","支持删除不需要的历史记录"]}]},aiGenerateCases:{title:"📖 AI 生成用例 - 使用说明",intro:"AI 生成用例功能可以根据 Swagger/OpenAPI 文档自动生成测试用例和场景链，大幅减少手工编写工作量。支持正向测试、异常测试、鉴权测试和边界测试。",sections:[{heading:"四步生成流程",icon:"🚀",steps:["**第 1 步 · 上传文档**：拖拽上传 Swagger/OpenAPI JSON/YAML 文件，或输入 Swagger URL 地址","**第 2 步 · 配置选项**：设置生成策略（每接口最大用例数、是否生成边界/鉴权/场景链测试）","**第 3 步 · AI 生成**：AI 逐接口分析并生成用例，实时显示进度和已生成用例预览","**第 4 步 · 预览 & 导入**：查看生成结果，选择导入分组，确认导入到用例库"]},{heading:"配置选项详解",icon:"⚙️",items:["**每接口最大用例数**：滑块调节（1-10），控制每个 API 生成多少条用例","**生成边界测试**：开启后 AI 会生成空值、超长字符串、类型错误等边界场景","**生成鉴权测试**：开启后 AI 会生成无 Token、过期 Token、无效 Token 等鉴权异常场景","**生成场景链**：开启后 AI 自动识别 CRUD 关系，编排为测试场景（如：创建→查询→修改→删除）"]},{heading:"生成过程",icon:"📊",text:"点击「开始生成」后，AI 按流水线模式工作：",items:["**阶段 1 · 分析**：解析 Swagger 文档，识别所有接口和参数","**阶段 2 · 生成用例**：逐接口生成测试用例，每批分析完立即生成","**阶段 3 · 生成场景**：如果开启了场景链，自动编排关联接口为测试场景","进度条实时显示完成百分比，已生成的用例会实时保存","如果中途点击「中止生成」，已生成的用例会保留，不会丢失"]},{heading:"预览与导入",icon:"📋",items:["**用例预览**：展开查看每条用例的 URL、请求体、断言规则、变量提取配置","**场景预览**：查看场景链的步骤编排","**导入分组名**：设置导入到接口库的分组名称，默认「AI生成用例」","**确认导入**：将所有生成的用例和场景导入到接口库","**重新生成**：不满意可返回第 1 步重新生成"]},{heading:"任务恢复",icon:"🔄",text:"生成过程中如果切换了页面或刷新了浏览器，重新进入 AI 生成页面时会自动检测未完成的任务并恢复进度。每个用户的任务独立存储，互不影响。"}]},testCoverage:{title:"📖 覆盖率看板 - 使用说明",intro:"覆盖率看板展示接口测试的覆盖情况和执行质量，帮助你发现未覆盖的接口和薄弱环节，持续提升测试质量。",sections:[{heading:"核心指标",icon:"📊",items:["**接口总数**：接口库中所有唯一的接口数（按 URL 去重）","**用例总数**：接口库中的测试用例总数","**30 天执行次数**：最近 30 天内的所有执行记录数","**通过率**：最近 30 天执行通过的比率（通过数 / 总执行数）"]},{heading:"热力图",icon:"🗺️",text:"热力图按「接口 × 日期」矩阵展示执行情况：",items:["**X 轴**：日期（可切换 7/14/30/90 天范围）","**Y 轴**：接口列表（按分组排列）","**颜色含义**：灰色 = 未执行、绿色 = 通过、红色 = 失败、橙色 = 未知状态","**点击单元格**：查看该接口在该日期的所有执行详情（ID、状态、响应时间、错误信息）","颜色越深表示执行越频繁，帮助识别高频和低频接口"]},{heading:"搜索与过滤",icon:"🔍",text:"顶部搜索框支持按接口名称、URL、请求方法过滤热力图中的接口行，快速定位目标接口。"},{heading:"分组统计",icon:"📁",text:"底部卡片按接口分组展示统计：每组的接口数量和平均通过率，帮助识别哪个模块的测试质量最差。"},{heading:"如何提升覆盖率",icon:"💡",items:["关注热力图中**灰色行**（从未执行的接口），优先为这些接口编写用例","关注**红色单元格**（执行失败），分析失败原因并修复用例或接口","设置**定时任务**让场景每天自动执行，保持覆盖率不下降","使用 **AI 生成用例**快速补充缺失的测试用例"]}]}},J={class:"help-drawer-content"},C=["innerHTML"],f={class:"help-section-title"},w={class:"section-icon"},O={class:"help-section-body"},E=["innerHTML"],D={key:1,class:"help-list"},N=["innerHTML"],v={key:2,class:"help-steps"},V=["innerHTML"],$={key:3,class:"help-code"},Y={key:1,class:"help-empty"},B={__name:"HelpDrawer",props:{modelValue:{type:Boolean,default:!1},title:{type:String,default:"📖 使用说明"},intro:{type:String,default:""},introTitle:{type:String,default:""},introType:{type:String,default:"info"},sections:{type:Array,default:()=>[]}},emits:["update:modelValue"],setup(n,{emit:b}){const L=n,S=b,u=I({get:()=>L.modelValue,set:l=>S("update:modelValue",l)}),r=l=>!l||typeof l!="string"?"":l.replace(/\n/g,"<br/>").replace(/`([^`]+)`/g,'<code class="help-inline-code">$1</code>').replace(/\*\*([^*]+)\*\*/g,"<strong>$1</strong>");return(l,x)=>{const T=M,_=P,k=R,U=A;return t(),c(U,{modelValue:u.value,"onUpdate:modelValue":x[0]||(x[0]=e=>u.value=e),title:n.title,direction:"rtl",size:"540px","with-header":!0,"destroy-on-close":!1,"custom-class":"help-drawer"},{default:m(()=>[o("div",J,[n.intro?(t(),c(T,{key:0,title:n.introTitle||"使用说明",type:n.introType||"info",closable:!1,"show-icon":"",class:"help-intro"},{default:m(()=>[o("div",{innerHTML:r(n.intro)},null,8,C)]),_:1},8,["title","type"])):s("",!0),(t(!0),i(p,null,d(n.sections,(e,y)=>(t(),i("div",{key:y,class:"help-section"},[o("h3",f,[o("span",w,g(e.icon||"📘"),1),o("span",null,g(e.heading),1)]),o("div",O,[e.text?(t(),i("p",{key:0,class:"help-paragraph",innerHTML:r(e.text)},null,8,E)):s("",!0),e.items&&e.items.length?(t(),i("ul",D,[(t(!0),i(p,null,d(e.items,(a,h)=>(t(),i("li",{key:h,innerHTML:r(a)},null,8,N))),128))])):s("",!0),e.steps&&e.steps.length?(t(),i("ol",v,[(t(!0),i(p,null,d(e.steps,(a,h)=>(t(),i("li",{key:h,innerHTML:r(a)},null,8,V))),128))])):s("",!0),e.code?(t(),i("div",$,[o("pre",null,g(e.code),1)])):s("",!0),e.table&&e.table.rows?(t(),c(k,{key:4,data:e.table.rows,border:"",size:"small",class:"help-table"},{default:m(()=>[(t(!0),i(p,null,d(e.table.cols,a=>(t(),c(_,{key:a.key,prop:a.key,label:a.label,"min-width":a.width||100},null,8,["prop","label","min-width"]))),128))]),_:2},1032,["data"])):s("",!0)])]))),128)),!n.sections||n.sections.length===0?(t(),i("div",Y," 暂无使用说明 ")):s("",!0)])]),_:1},8,["modelValue","title"])}}},z=H(B,[["__scopeId","data-v-d1b4ec4e"]]);export{z as H,G as h};
